# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import io
import json
import threading
from collections import defaultdict, Counter
from datetime import datetime
from flask import Flask, request, jsonify
import numpy as np
from PIL import Image
import torch
import torch.nn as nn
import torch.optim as optim
from torchvision import transforms, models

app = Flask(__name__)

# Data structures
annotations_db = defaultdict(list)  # image_id -> list of (annotator_id, label, timestamp)
images_db = {}  # image_id -> image_data
aggregated_labels = {}  # image_id -> final_label
annotators_stats = defaultdict(lambda: {"total": 0, "images": set()})

lock = threading.Lock()

# Model configuration
device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
model = None
num_classes = 10  # Default, can be configured


class SimpleClassifier(nn.Module):
    def __init__(self, num_classes):
        super(SimpleClassifier, self).__init__()
        self.base_model = models.resnet18(weights=None)
        self.base_model.fc = nn.Linear(self.base_model.fc.in_features, num_classes)
    
    def forward(self, x):
        return self.base_model(x)


def initialize_model(num_classes_param):
    global model, num_classes
    num_classes = num_classes_param
    model = SimpleClassifier(num_classes).to(device)
    return model


@app.route('/upload_image', methods=['POST'])
def upload_image():
    """Upload an image to be labeled"""
    try:
        if 'image' not in request.files:
            return jsonify({"error": "No image file provided"}), 400
        
        image_file = request.files['image']
        image_id = request.form.get('image_id')
        
        if not image_id:
            return jsonify({"error": "image_id is required"}), 400
        
        # Read and store image
        image_data = image_file.read()
        
        with lock:
            images_db[image_id] = image_data
        
        return jsonify({
            "status": "success",
            "image_id": image_id,
            "message": "Image uploaded successfully"
        }), 200
    
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route('/annotate', methods=['POST'])
def annotate():
    """Submit an annotation for an image"""
    try:
        data = request.json
        
        if not data:
            return jsonify({"error": "No JSON data provided"}), 400
        
        image_id = data.get('image_id')
        annotator_id = data.get('annotator_id')
        label = data.get('label')
        
        if not all([image_id, annotator_id, label is not None]):
            return jsonify({"error": "image_id, annotator_id, and label are required"}), 400
        
        with lock:
            if image_id not in images_db:
                return jsonify({"error": "Image not found"}), 404
            
            # Store annotation
            timestamp = datetime.now().isoformat()
            annotations_db[image_id].append({
                "annotator_id": annotator_id,
                "label": label,
                "timestamp": timestamp
            })
            
            # Update annotator stats
            annotators_stats[annotator_id]["total"] += 1
            annotators_stats[annotator_id]["images"].add(image_id)
            
            # Aggregate labels
            aggregate_labels_for_image(image_id)
        
        return jsonify({
            "status": "success",
            "image_id": image_id,
            "annotator_id": annotator_id,
            "total_annotations": len(annotations_db[image_id])
        }), 200
    
    except Exception as e:
        return jsonify({"error": str(e)}), 500


def aggregate_labels_for_image(image_id):
    """Aggregate labels for a single image using majority voting"""
    annotations = annotations_db[image_id]
    
    if not annotations:
        return None
    
    # Extract labels
    labels = [ann["label"] for ann in annotations]
    
    # Majority voting
    label_counts = Counter(labels)
    most_common_label, count = label_counts.most_common(1)[0]
    
    aggregated_labels[image_id] = {
        "label": most_common_label,
        "vote_count": count,
        "total_annotations": len(annotations),
        "confidence": count / len(annotations)
    }
    
    return aggregated_labels[image_id]


@app.route('/aggregate_all', methods=['POST'])
def aggregate_all():
    """Aggregate labels for all images"""
    try:
        with lock:
            for image_id in annotations_db.keys():
                aggregate_labels_for_image(image_id)
        
        return jsonify({
            "status": "success",
            "total_images": len(aggregated_labels),
            "message": "All labels aggregated successfully"
        }), 200
    
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route('/get_annotations/<image_id>', methods=['GET'])
def get_annotations(image_id):
    """Get all annotations for a specific image"""
    with lock:
        if image_id not in annotations_db:
            return jsonify({"error": "Image not found"}), 404
        
        annotations = annotations_db[image_id]
        aggregated = aggregated_labels.get(image_id, None)
    
    return jsonify({
        "image_id": image_id,
        "annotations": annotations,
        "aggregated_label": aggregated
    }), 200


@app.route('/get_aggregated_labels', methods=['GET'])
def get_aggregated_labels():
    """Get all aggregated labels"""
    with lock:
        labels_copy = dict(aggregated_labels)
    
    return jsonify({
        "total_images": len(labels_copy),
        "aggregated_labels": labels_copy
    }), 200


@app.route('/annotator_stats/<annotator_id>', methods=['GET'])
def get_annotator_stats(annotator_id):
    """Get statistics for a specific annotator"""
    with lock:
        if annotator_id not in annotators_stats:
            return jsonify({"error": "Annotator not found"}), 404
        
        stats = annotators_stats[annotator_id].copy()
        stats["images"] = list(stats["images"])
    
    return jsonify({
        "annotator_id": annotator_id,
        "total_annotations": stats["total"],
        "unique_images": len(stats["images"])
    }), 200


@app.route('/train_model', methods=['POST'])
def train_model_endpoint():
    """Train model on aggregated labeled data"""
    try:
        data = request.json or {}
        epochs = data.get('epochs', 10)
        batch_size = data.get('batch_size', 32)
        learning_rate = data.get('learning_rate', 0.001)
        num_classes_param = data.get('num_classes', 10)
        
        with lock:
            if not aggregated_labels:
                return jsonify({"error": "No aggregated labels available"}), 400
            
            # Prepare training data
            train_images = []
            train_labels = []
            
            for image_id, label_info in aggregated_labels.items():
                if image_id in images_db:
                    train_images.append(images_db[image_id])
                    train_labels.append(label_info["label"])
            
            if not train_images:
                return jsonify({"error": "No training data available"}), 400
        
        # Initialize model
        initialize_model(num_classes_param)
        
        # Train model
        training_stats = train_model_internal(
            train_images, 
            train_labels, 
            epochs, 
            batch_size, 
            learning_rate
        )
        
        return jsonify({
            "status": "success",
            "training_stats": training_stats,
            "total_samples": len(train_images)
        }), 200
    
    except Exception as e:
        return jsonify({"error": str(e)}), 500


def train_model_internal(image_data_list, labels, epochs, batch_size, learning_rate):
    """Internal function to train the model"""
    global model
    
    # Image preprocessing
    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])
    
    # Prepare dataset
    processed_images = []
    processed_labels = []
    
    for img_data, label in zip(image_data_list, labels):
        try:
            img = Image.open(io.BytesIO(img_data)).convert('RGB')
            img_tensor = transform(img)
            processed_images.append(img_tensor)
            processed_labels.append(label)
        except Exception as e:
            continue
    
    if not processed_images:
        raise ValueError("No valid images to train on")
    
    # Stack images
    images_tensor = torch.stack(processed_images)
    labels_tensor = torch.tensor(processed_labels, dtype=torch.long)
    
    # Create dataset
    dataset = torch.utils.data.TensorDataset(images_tensor, labels_tensor)
    dataloader = torch.utils.data.DataLoader(
        dataset, 
        batch_size=batch_size, 
        shuffle=True
    )
    
    # Training setup
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)
    
    model.train()
    
    training_stats = {
        "epochs": [],
        "losses": []
    }
    
    for epoch in range(epochs):
        epoch_loss = 0.0
        num_batches = 0
        
        for batch_images, batch_labels in dataloader:
            batch_images = batch_images.to(device)
            batch_labels = batch_labels.to(device)
            
            optimizer.zero_grad()
            outputs = model(batch_images)
            loss = criterion(outputs, batch_labels)
            loss.backward()
            optimizer.step()
            
            epoch_loss += loss.item()
            num_batches += 1
        
        avg_loss = epoch_loss / num_batches
        training_stats["epochs"].append(epoch + 1)
        training_stats["losses"].append(avg_loss)
    
    return training_stats


@app.route('/predict', methods=['POST'])
def predict():
    """Make predictions on a new image"""
    try:
        if model is None:
            return jsonify({"error": "Model not trained yet"}), 400
        
        if 'image' not in request.files:
            return jsonify({"error": "No image file provided"}), 400
        
        image_file = request.files['image']
        image_data = image_file.read()
        
        # Preprocess image
        transform = transforms.Compose([
            transforms.Resize((224, 224)),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        img = Image.open(io.BytesIO(image_data)).convert('RGB')
        img_tensor = transform(img).unsqueeze(0).to(device)
        
        # Make prediction
        model.eval()
        with torch.no_grad():
            outputs = model(img_tensor)
            probabilities = torch.softmax(outputs, dim=1)
            predicted_class = torch.argmax(probabilities, dim=1).item()
            confidence = probabilities[0][predicted_class].item()
        
        return jsonify({
            "predicted_class": predicted_class,
            "confidence": confidence,
            "all_probabilities": probabilities[0].cpu().numpy().tolist()
        }), 200
    
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route('/stats', methods=['GET'])
def get_stats():
    """Get overall system statistics"""
    with lock:
        total_images = len(images_db)
        total_annotations = sum(len(anns) for anns in annotations_db.values())
        total_annotators = len(annotators_stats)
        images_with_aggregated_labels = len(aggregated_labels)
    
    return jsonify({
        "total_images": total_images,
        "total_annotations": total_annotations,
        "total_annotators": total_annotators,
        "images_with_aggregated_labels": images_with_aggregated_labels,
        "model_trained": model is not None
    }), 200


@app.route('/reset', methods=['POST'])
def reset():
    """Reset all data"""
    global annotations_db, images_db, aggregated_labels, annotators_stats, model
    
    with lock:
        annotations_db.clear()
        images_db.clear()
        aggregated_labels.clear()
        annotators_stats.clear()
        model = None
    
    return jsonify({"status": "success", "message": "All data reset"}), 200


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)